import React, { useEffect } from 'react';
import { OIDC_CONFIG } from '../config';
import { generateCodeChallenge, generateCodeVerifier, generateRandomString } from '../utils/oidc';

const Login = () => {
  useEffect(() => {
    const initiateOidcLogin = async () => {
      const codeVerifier = generateCodeVerifier();
      const codeChallenge = generateCodeChallenge(codeVerifier);
      const state = generateRandomString(32); // CSRF protection

      sessionStorage.setItem('oidcCodeVerifier', codeVerifier);
      sessionStorage.setItem('oidcState', state);

      const params = new URLSearchParams({
        client_id: OIDC_CONFIG.CLIENT_ID,
        redirect_uri: OIDC_CONFIG.REDIRECT_URI,
        response_type: OIDC_CONFIG.RESPONSE_TYPE,
        scope: OIDC_CONFIG.SCOPE,
        code_challenge: codeChallenge,
        code_challenge_method: OIDC_CONFIG.CODE_CHALLENGE_METHOD,
        state: state,
      });

      window.location.href = `${OIDC_CONFIG.AUTHORIZATION_ENDPOINT}?${params.toString()}`;
    };

    initiateOidcLogin();
  }, []);

  return (
    <div>
      <p>Redirecting to login...</p>
    </div>
  );
};

export default Login;


// src/pages/Callback.js
import React, { useEffect } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { OIDC_CONFIG } from '../config';
import { useAuth } from '../context/AuthContext';

const Callback = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { saveAuthData } = useAuth();

  useEffect(() => {
    const handleCallback = async () => {
      const code = searchParams.get('code');
      const state = searchParams.get('state');
      const error = searchParams.get('error');

      if (error) {
        console.error('OIDC Error:', error, searchParams.get('error_description'));
        navigate('/'); // Redirect to home or an error page
        return;
      }

      const storedState = sessionStorage.getItem('oidcState');
      if (state !== storedState) {
        console.error('State mismatch. Possible CSRF attack.');
        navigate('/');
        return;
      }
      sessionStorage.removeItem('oidcState'); // Clear state after validation

      if (code) {
        const codeVerifier = sessionStorage.getItem('oidcCodeVerifier');
        if (!codeVerifier) {
          console.error('Code verifier not found in session storage.');
          navigate('/');
          return;
        }
        sessionStorage.removeItem('oidcCodeVerifier'); // Clear verifier after use

        try {
          const params = new URLSearchParams();
          params.append('client_id', OIDC_CONFIG.CLIENT_ID);
          params.append('code', code);
          params.append('redirect_uri', OIDC_CONFIG.REDIRECT_URI);
          params.append('grant_type', 'authorization_code');
          params.append('code_verifier', codeVerifier);

          const response = await fetch(OIDC_CONFIG.TOKEN_ENDPOINT, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/x-www-form-urlencoded',
            },
            body: params.toString(),
          });

          if (!response.ok) {
            const errorData = await response.json();
            console.error('Token exchange failed:', errorData);
            throw new Error(`Token exchange failed: ${errorData.error_description || response.statusText}`);
          }

          const tokens = await response.json();
          saveAuthData(tokens);
          navigate('/'); // Redirect to home page after successful login
        } catch (error) {
          console.error('Error exchanging code for tokens:', error);
          navigate('/'); // Redirect to home on error
        }
      } else {
        navigate('/'); // If no code, something went wrong, go to home
      }
    };

    handleCallback();
  }, [searchParams, navigate, saveAuthData]);

  return <div>Processing login callback...</div>;
};

export default Callback;


